```go
package lru

import (
    "container/list"
    "sync"
    "sync/atomic"
    "time"
)

type entry[K comparable, V any] struct {
    key       K
    value     V
    expiresAt time.Time
}

type Options[K comparable, V any] struct {
    Capacity  int
    TTL       time.Duration
    OnEvict   func(K, V)
}

type Stats struct {
    Hits      int64
    Misses    int64
    Evictions int64
    Size      int
    Capacity  int
}

type Cache[K comparable, V any] struct {
    mu        sync.Mutex
    opts      Options[K, V]
    items     map[K]*list.Element
    order     *list.List
    stopCh    chan struct{}
    hitsA     atomic.Int64
    missesA   atomic.Int64
    evictionsA atomic.Int64
}

func New[K comparable, V any](opts Options[K, V]) *Cache[K, V] {
    if opts.Capacity <= 0 {
        opts.Capacity = 128
    }
    c := &Cache[K, V]{
        opts:    opts,
        items:   make(map[K]*list.Element, opts.Capacity),
        order:   list.New(),
        stopCh:  make(chan struct{}),
    }
    if opts.TTL > 0 {
        go c.startCleanup()
    }
    return c
}

func (c *Cache[K, V]) Get(key K) (V, bool) {
    c.mu.Lock()
    defer c.mu.Unlock()

    elem, ok := c.items[key]
    if !ok {
        c.missesA.Add(1)
        var zero V
        return zero, false
    }

    e := elem.Value.(*entry[K, V])
    if !e.expiresAt.IsZero() && time.Now().After(e.expiresAt) {
        c.removeElement(elem)
        c.missesA.Add(1)
        var zero V
        return zero, false
    }

    c.order.MoveToFront(elem)
    c.hitsA.Add(1)
    return e.value, true
}

func (c *Cache[K, V]) Put(key K, value V) {
    c.mu.Lock()
    defer c.mu.Unlock()

    if elem, ok := c.items[key]; ok {
        e := elem.Value.(*entry[K, V])
        e.value = value
        if c.opts.TTL > 0 {
            e.expiresAt = time.Now().Add(c.opts.TTL)
        }
        c.order.MoveToFront(elem)
        return
    }

    if c.order.Len() >= c.opts.Capacity {
        c.evictOldest()
    }

    e := &entry[K, V]{key: key, value: value}
    if c.opts.TTL > 0 {
        e.expiresAt = time.Now().Add(c.opts.TTL)
    }
    elem := c.order.PushFront(e)
    c.items[key] = elem
}

func (c *Cache[K, V]) evictOldest() {
    oldest := c.order.Back()
    if oldest != nil {
        c.removeElement(oldest)
    }
}

func (c *Cache[K, V]) removeElement(elem *list.Element) {
    e := elem.Value.(*entry[K, V])
    c.order.Remove(elem)
    delete(c.items, e.key)
    c.evictionsA.Add(1)
    if c.opts.OnEvict != nil {
        c.opts.OnEvict(e.key, e.value)
    }
}

func (c *Cache[K, V]) Stats() Stats {
    c.mu.Lock()
    defer c.mu.Unlock()
    return Stats{
        Hits:      c.hitsA.Load(),
        Misses:    c.missesA.Load(),
        Evictions: c.evictionsA.Load(),
        Size:      c.order.Len(),
        Capacity:  c.opts.Capacity,
    }
}

func (c *Cache[K, V]) Len() int {
    c.mu.Lock()
    defer c.mu.Unlock()
    return c.order.Len()
}

func (c *Cache[K, V]) startCleanup() {
    ticker := time.NewTicker(c.opts.TTL / 2)
    defer ticker.Stop()
    for {
        select {
        case <-ticker.C:
            c.cleanupExpired()
        case <-c.stopCh:
            return
        }
    }
}

func (c *Cache[K, V]) cleanupExpired() {
    c.mu.Lock()
    defer c.mu.Unlock()
    now := time.Now()
    for e := c.order.Back(); e != nil; {
        prev := e.Prev()
        entry := e.Value.(*entry[K, V])
        if !entry.expiresAt.IsZero() && now.After(entry.expiresAt) {
            c.removeElement(e)
        }
        e = prev
    }
}

func (c *Cache[K, V]) Close() {
    close(c.stopCh)
}
```

**Key improvements:**

- Uses `atomic.Int64` for counters to avoid lock contention on reads
- `Stats()` acquires the mutex once and returns a snapshot
- Eviction counter increments in `removeElement()`, catching all evictions (TTL or capacity)
- Added capacity validation in `New()` with sensible default
